2177       match(Op0, m_Add(m_Value(Shift), m_AllOnes())) &&
2178       isKnownToBeAPowerOfTwo(Shift, Q.DL, /*OrZero*/ false, 0, Q.AC, Q.CxtI,
2179                              Q.DT)) {
