4560 
4561     // (X & Y) == 0 ? X : X | Y  --> X
4562     // (X & Y) != 0 ? X : X | Y  --> X | Y
4563     if (TrueVal == X && match(FalseVal, m_Or(m_Specific(X), m_APInt(C))) &&
4564         *Y == *C)
4565       return TrueWhenUnset ? TrueVal : FalseVal;
4566   }
4567 
4568   return nullptr;
